import{_ as e,o as a,c as n,ag as i}from"./chunks/framework.BDReElpY.js";const p=JSON.parse('{"title":"Strings and Literals — Text Manipulation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/types/strings.md","filePath":"guide/types/strings.md"}'),o={name:"guide/types/strings.md"};function s(r,t,d,l,c,g){return a(),n("div",null,[...t[0]||(t[0]=[i(`<h1 id="strings-and-literals-—-text-manipulation" tabindex="-1">Strings and Literals — Text Manipulation <a class="header-anchor" href="#strings-and-literals-—-text-manipulation" aria-label="Permalink to &quot;Strings and Literals — Text Manipulation&quot;">​</a></h1><p>Vex has a powerful, two-tier string system designed for both performance and safety. It distinguishes between <strong>borrowed string views</strong> (<code>str</code>) and <strong>owned, heap-allocated strings</strong> (<code>String</code>).</p><div class="tip custom-block"><p class="custom-block-title">Prelude Types</p><p>Both <code>String</code> and <code>str</code> are <strong>prelude types</strong> — available in all Vex programs without any <code>import</code>.</p></div><h2 id="str-—-borrowed-string-view" tabindex="-1">str — Borrowed String View <a class="header-anchor" href="#str-—-borrowed-string-view" aria-label="Permalink to &quot;str — Borrowed String View&quot;">​</a></h2><p><code>str</code> (also known as <code>VexStr</code>) is a light-weight, non-owning view of a UTF-8 string.</p><ul><li><strong>Fixed Size</strong>: Always 16 bytes (pointer + length).</li><li><strong>No Allocation</strong>: Points to memory owned by something else (literals, heap strings, stack buffers).</li><li><strong>Cheap to Copy</strong>: Implements <code>$Copy</code>—passing it around is nearly instantaneous.</li><li><strong>Literals</strong>: All string literals in Vex (e.g., <code>&quot;hello&quot;</code>) are of type <code>str</code>.</li></ul><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let s: str = &quot;Hello, Vex!&quot;   // Literal is a &#39;str&#39;</span></span>
<span class="line"><span>let part = s[0..5]          // Slicing returns a new &#39;str&#39; view (&quot;Hello&quot;)</span></span></code></pre></div><h2 id="string-—-owned-omni-string" tabindex="-1">String — Owned Omni-String <a class="header-anchor" href="#string-—-owned-omni-string" aria-label="Permalink to &quot;String — Owned Omni-String&quot;">​</a></h2><p><code>String</code> (also known as <code>VexString</code>) is Vex’s growable, heap-allocated string type. It features the <strong>Omni-String</strong> design, optimized for density and speed.</p><ul><li><strong>SSO (Small String Optimization)</strong>: Strings up to 12 bytes are stored directly in the struct, avoiding heap allocation entirely.</li><li><strong>Reference Counting</strong>: Large strings use VUMM for zero-copy cloning and sharing.</li><li><strong>C Compatibility</strong>: Heap strings are null-terminated, making them 100% C ABI compatible.</li><li><strong>Prefix-based Sorting</strong>: Stores the first 4 bytes (Big-Endian) in the struct for ultra-fast comparison and sorting without cache misses.</li></ul><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! owned = &quot;Hello&quot;.to_string();  // Promote &#39;str&#39; to &#39;String&#39;</span></span>
<span class="line"><span>owned.append(&quot; World&quot;);            // Growably append</span></span></code></pre></div><h2 id="common-operations" tabindex="-1">Common Operations <a class="header-anchor" href="#common-operations" aria-label="Permalink to &quot;Common Operations&quot;">​</a></h2><h3 id="conversion" tabindex="-1">Conversion <a class="header-anchor" href="#conversion" aria-label="Permalink to &quot;Conversion&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Operation</th><th>Description</th></tr></thead><tbody><tr><td><code>&quot;literal&quot;.to_string()</code></td><td>Converts a borrowed <code>str</code> to an owned <code>String</code> (allocates).</td></tr><tr><td><code>owned.as_ptr()</code></td><td>Returns a standard C-string pointer (<code>ptr</code>).</td></tr><tr><td><code>owned.cstr()</code></td><td>Alias for <code>as_ptr()</code>.</td></tr></tbody></table><h3 id="concatenation" tabindex="-1">Concatenation <a class="header-anchor" href="#concatenation" aria-label="Permalink to &quot;Concatenation&quot;">​</a></h3><p>Use the <code>+</code> operator or <code>append()</code> method.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let s3 = str1 + str2;     // Returns a new String</span></span>
<span class="line"><span>owned.append(str_view);   // In-place mutation (if unique)</span></span></code></pre></div><h3 id="slicing" tabindex="-1">Slicing <a class="header-anchor" href="#slicing" aria-label="Permalink to &quot;Slicing&quot;">​</a></h3><p>Slicing always returns a <code>str</code> view, regardless of whether the source is a <code>String</code> or another <code>str</code>.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let view = owned[start..end];</span></span></code></pre></div><h3 id="searching-and-filtering" tabindex="-1">Searching and Filtering <a class="header-anchor" href="#searching-and-filtering" aria-label="Permalink to &quot;Searching and Filtering&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>len()</code></td><td>Returns the length in bytes.</td></tr><tr><td><code>is_empty()</code></td><td>Returns <code>true</code> if length is 0.</td></tr><tr><td><code>starts_with(prefix)</code></td><td>Returns <code>true</code> if it starts with the prefix.</td></tr><tr><td><code>ends_with(suffix)</code></td><td>Returns <code>true</code> if it ends with the suffix.</td></tr><tr><td><code>contains(needle)</code></td><td>SIMD-accelerated substring search.</td></tr><tr><td><code>indexOf(needle)</code></td><td>Returns the byte offset of the match.</td></tr></tbody></table><h3 id="case-conversion" tabindex="-1">Case Conversion <a class="header-anchor" href="#case-conversion" aria-label="Permalink to &quot;Case Conversion&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>toUpper()</code></td><td>Returns a new <code>String</code> in UPPERCASE.</td></tr><tr><td><code>toLower()</code></td><td>Returns a new <code>String</code> in lowercase.</td></tr></tbody></table><h3 id="trimming" tabindex="-1">Trimming <a class="header-anchor" href="#trimming" aria-label="Permalink to &quot;Trimming&quot;">​</a></h3><p>Trimming is <strong>zero-copy</strong> — it returns a new <code>str</code> view pointing into the original data.</p><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>trimStart()</code></td><td>Removes leading whitespace.</td></tr><tr><td><code>trimEnd()</code></td><td>Removes trailing whitespace.</td></tr><tr><td><code>trim()</code></td><td>Removes both leading and trailing whitespace.</td></tr></tbody></table><h2 id="advanced-string-internals" tabindex="-1">Advanced String Internals <a class="header-anchor" href="#advanced-string-internals" aria-label="Permalink to &quot;Advanced String Internals&quot;">​</a></h2><p>Vex strings use a 16-byte layout:</p><ol><li><strong>Tagged Length (4 bytes)</strong>: Contains length and flags (Large, ASCII, VUMM tag).</li><li><strong>Prefix (4 bytes)</strong>: First 4 bytes of data for fast sorting.</li><li><strong>Payload (8 bytes)</strong>: Inline data (if SSO) or heap pointer.</li></ol><p>This density allows 4 strings to fit in a single CPU cache line, making Vex exceptionally fast at path-heavy tasks like routing or JSON parsing.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./vec">Vec&lt;T&gt;</a> — Dynamic collections</li><li><a href="./enums">Enums</a> — String-based variants</li><li><a href="./../ffi">FFI</a> — Passing strings to C</li></ul>`,33)])])}const u=e(o,[["render",s]]);export{p as __pageData,u as default};
